internal fun localizedNameForRegion_normal_pis(
  query: Int,
  script: Int,
  region: Int,
  variant: Int,
): String? {
  if (region != 0 || script != 0 || variant != 0) {
    return null
  }
  return when (query) {
    254 -> "Solomon Aelan" // SB
    else -> null
  }
}

